// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";
import bcrypt from "bcryptjs";
import jwt from "jsonwebtoken";

const app = express();
const PORT = Number(process.env.PORT) || 3000;
const db: Database.Database = new Database("data.db");
const JWT_SECRET = "benchmark-secret";

db.pragma("journal_mode = WAL");
db.pragma("foreign_keys = ON");
db.exec(`
  CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL REFERENCES users(id),
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL REFERENCES users(id),
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER REFERENCES folders(id),
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

const bookmarkColumns = db.prepare("PRAGMA table_info(bookmarks)").all() as { name: string }[];
if (!bookmarkColumns.some((column) => column.name === "folder_id")) {
  db.prepare("ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id)").run();
}
if (!bookmarkColumns.some((column) => column.name === "user_id")) {
  db.prepare("ALTER TABLE bookmarks ADD COLUMN user_id INTEGER REFERENCES users(id)").run();
}

const folderColumns = db.prepare("PRAGMA table_info(folders)").all() as { name: string }[];
if (!folderColumns.some((column) => column.name === "user_id")) {
  db.prepare("ALTER TABLE folders ADD COLUMN user_id INTEGER REFERENCES users(id)").run();
}

app.use(express.json());

type AuthenticatedRequest = express.Request & {
  user: UserPublic;
};

type UserRow = {
  id: number;
  email: string;
  password_hash: string;
  created_at: string;
};

type UserPublic = Omit<UserRow, "password_hash">;

type AuthRequestBody = {
  email?: unknown;
  password?: unknown;
};

type BookmarkRow = {
  id: number;
  user_id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type BookmarkRequestBody = {
  url?: unknown;
  title?: unknown;
  description?: unknown;
  folder_id?: unknown;
};

type FolderRow = {
  id: number;
  user_id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type FolderWithBookmarks = FolderRow & {
  bookmarks: BookmarkRow[];
};

type FolderRequestBody = {
  name?: unknown;
};

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

function requestBodyObject(value: unknown): Record<string, unknown> {
  if (value !== null && typeof value === "object" && !Array.isArray(value)) {
    return value as Record<string, unknown>;
  }

  return {};
}

function isValidEmail(value: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
}

function isValidUrl(value: string): boolean {
  try {
    new URL(value);
    return true;
  } catch {
    return false;
  }
}

function publicUser(user: UserRow): UserPublic {
  return {
    id: user.id,
    email: user.email,
    created_at: user.created_at,
  };
}

function findUserByEmail(email: string): UserRow | undefined {
  return db.prepare("SELECT * FROM users WHERE email = ?").get(email) as UserRow | undefined;
}

function findUserById(id: number): UserRow | undefined {
  return db.prepare("SELECT * FROM users WHERE id = ?").get(id) as UserRow | undefined;
}

function parseAuthInput(body: AuthRequestBody): { email: string; password: string } | { error: string } {
  if (!isNonEmptyString(body.email) || !isValidEmail(body.email.trim())) {
    return { error: "valid email is required" };
  }

  if (typeof body.password !== "string" || body.password.length < 8) {
    return { error: "password must be at least 8 characters" };
  }

  return {
    email: body.email.trim().toLowerCase(),
    password: body.password,
  };
}

function authenticate(req: express.Request, res: express.Response, next: express.NextFunction) {
  const authorization = req.header("Authorization");

  if (!authorization?.startsWith("Bearer ")) {
    return res.status(401).json({ error: "authentication required" });
  }

  const token = authorization.slice("Bearer ".length).trim();

  try {
    const payload = jwt.verify(token, JWT_SECRET);

    if (typeof payload !== "object" || payload === null || typeof payload.userId !== "number") {
      return res.status(401).json({ error: "invalid token" });
    }

    const user = findUserById(payload.userId);

    if (!user) {
      return res.status(401).json({ error: "invalid token" });
    }

    (req as AuthenticatedRequest).user = publicUser(user);
    return next();
  } catch {
    return res.status(401).json({ error: "invalid token" });
  }
}

function authenticatedUserId(req: express.Request): number {
  return (req as unknown as AuthenticatedRequest).user.id;
}

function parseOptionalFolderId(value: unknown): number | null | undefined {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  if (typeof value !== "number" || !Number.isInteger(value)) {
    return undefined;
  }

  return value;
}

function validateBookmarkInput(userId: number, body: BookmarkRequestBody, partial = false): string | null {
  if (!partial || body.url !== undefined) {
    if (!isNonEmptyString(body.url)) {
      return "url must be a non-empty string";
    }

    if (!isValidUrl(body.url.trim())) {
      return "url must be valid";
    }
  }

  if (!partial || body.title !== undefined) {
    if (!isNonEmptyString(body.title)) {
      return "title must be a non-empty string";
    }
  }

  if (body.description !== undefined && body.description !== null && typeof body.description !== "string") {
    return "description must be a string";
  }

  if (body.folder_id !== undefined) {
    const folderId = parseOptionalFolderId(body.folder_id);

    if (folderId === undefined) {
      return "folder_id must be an integer or null";
    }

    if (folderId !== null && !findFolder(userId, folderId)) {
      return "folder_id does not reference an existing folder";
    }
  }

  return null;
}

function findBookmark(userId: number, id: number): BookmarkRow | undefined {
  return db.prepare("SELECT * FROM bookmarks WHERE user_id = ? AND id = ?").get(userId, id) as
    | BookmarkRow
    | undefined;
}

function findFolder(userId: number, id: number): FolderRow | undefined {
  return db.prepare("SELECT * FROM folders WHERE user_id = ? AND id = ?").get(userId, id) as
    | FolderRow
    | undefined;
}

function findFolderWithBookmarks(userId: number, id: number): FolderWithBookmarks | undefined {
  const folder = findFolder(userId, id);

  if (!folder) {
    return undefined;
  }

  const bookmarks = db
    .prepare("SELECT * FROM bookmarks WHERE user_id = ? AND folder_id = ? ORDER BY id ASC")
    .all(userId, id) as BookmarkRow[];

  return { ...folder, bookmarks };
}

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/auth/register", (req, res) => {
  const parsed = parseAuthInput(requestBodyObject(req.body) as AuthRequestBody);

  if ("error" in parsed) {
    return res.status(400).json({ error: parsed.error });
  }

  if (findUserByEmail(parsed.email)) {
    return res.status(409).json({ error: "email already exists" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      `
        INSERT INTO users (email, password_hash, created_at)
        VALUES (?, ?, ?)
      `,
    )
    .run(parsed.email, bcrypt.hashSync(parsed.password, 10), now);

  const user = findUserById(Number(result.lastInsertRowid));
  return res.status(201).json(user ? publicUser(user) : null);
});

app.post("/auth/login", (req, res) => {
  const parsed = parseAuthInput(requestBodyObject(req.body) as AuthRequestBody);

  if ("error" in parsed) {
    return res.status(400).json({ error: parsed.error });
  }

  const user = findUserByEmail(parsed.email);

  if (!user || !bcrypt.compareSync(parsed.password, user.password_hash)) {
    return res.status(401).json({ error: "invalid credentials" });
  }

  const token = jwt.sign({ userId: user.id }, JWT_SECRET);
  return res.status(200).json({ token });
});

app.use("/folders", authenticate);
app.use("/bookmarks", authenticate);

app.post("/folders", (req, res) => {
  const userId = authenticatedUserId(req);
  const body = requestBodyObject(req.body) as FolderRequestBody;

  if (!isNonEmptyString(body.name)) {
    return res.status(400).json({ error: "name must be a non-empty string" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      `
        INSERT INTO folders (user_id, name, created_at, updated_at)
        VALUES (?, ?, ?, ?)
      `,
    )
    .run(userId, body.name.trim(), now, now);

  return res.status(201).json(findFolder(userId, Number(result.lastInsertRowid)));
});

app.get("/folders", (req, res) => {
  const userId = authenticatedUserId(req);
  const folders = db
    .prepare("SELECT * FROM folders WHERE user_id = ? ORDER BY id ASC")
    .all(userId) as FolderRow[];
  return res.status(200).json(folders);
});

app.get("/folders/:id", (req, res) => {
  const userId = authenticatedUserId(req);
  const folder = findFolderWithBookmarks(userId, Number(req.params.id));

  if (!folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  return res.status(200).json(folder);
});

app.put("/folders/:id", (req, res) => {
  const userId = authenticatedUserId(req);
  const id = Number(req.params.id);
  const existing = findFolder(userId, id);

  if (!existing) {
    return res.status(404).json({ error: "folder not found" });
  }

  const body = requestBodyObject(req.body) as FolderRequestBody;

  if (body.name !== undefined && !isNonEmptyString(body.name)) {
    return res.status(400).json({ error: "name must be a non-empty string" });
  }

  if (body.name === undefined) {
    return res.status(200).json(existing);
  }

  db.prepare(
    `
      UPDATE folders
      SET name = ?, updated_at = ?
      WHERE user_id = ? AND id = ?
    `,
  ).run(body.name.trim(), new Date().toISOString(), userId, id);

  return res.status(200).json(findFolder(userId, id));
});

app.delete("/folders/:id", (req, res) => {
  const userId = authenticatedUserId(req);
  const id = Number(req.params.id);
  const existing = findFolder(userId, id);

  if (!existing) {
    return res.status(404).json({ error: "folder not found" });
  }

  const deleteFolder = db.transaction(() => {
    db.prepare("UPDATE bookmarks SET folder_id = NULL, updated_at = ? WHERE user_id = ? AND folder_id = ?").run(
      new Date().toISOString(),
      userId,
      id,
    );
    db.prepare("DELETE FROM folders WHERE user_id = ? AND id = ?").run(userId, id);
  });

  deleteFolder();
  return res.status(204).send();
});

app.post("/bookmarks", (req, res) => {
  const userId = authenticatedUserId(req);
  const body = requestBodyObject(req.body) as BookmarkRequestBody;
  const validationError = validateBookmarkInput(userId, body);

  if (validationError) {
    return res.status(400).json({ error: validationError });
  }

  const now = new Date().toISOString();
  const folderId = parseOptionalFolderId(body.folder_id) ?? null;
  const result = db
    .prepare(
      `
        INSERT INTO bookmarks (user_id, url, title, description, folder_id, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?)
      `,
    )
    .run(
      userId,
      (body.url as string).trim(),
      (body.title as string).trim(),
      typeof body.description === "string" ? body.description : null,
      folderId,
      now,
      now,
    );

  const bookmark = findBookmark(userId, Number(result.lastInsertRowid));
  return res.status(201).json(bookmark);
});

app.get("/bookmarks", (req, res) => {
  const userId = authenticatedUserId(req);
  const bookmarks = db
    .prepare("SELECT * FROM bookmarks WHERE user_id = ? ORDER BY id ASC")
    .all(userId) as BookmarkRow[];
  res.status(200).json(bookmarks);
});

app.get("/bookmarks/:id", (req, res) => {
  const userId = authenticatedUserId(req);
  const bookmark = findBookmark(userId, Number(req.params.id));

  if (!bookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const userId = authenticatedUserId(req);
  const id = Number(req.params.id);
  const existing = findBookmark(userId, id);

  if (!existing) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const body = requestBodyObject(req.body) as BookmarkRequestBody;
  const validationError = validateBookmarkInput(userId, body, true);

  if (validationError) {
    return res.status(400).json({ error: validationError });
  }

  const updatedBookmark = {
    url: body.url === undefined ? existing.url : (body.url as string).trim(),
    title: body.title === undefined ? existing.title : (body.title as string).trim(),
    description:
      body.description === undefined
        ? existing.description
        : typeof body.description === "string"
          ? body.description
          : null,
    folder_id: body.folder_id === undefined ? existing.folder_id : parseOptionalFolderId(body.folder_id),
    updated_at: new Date().toISOString(),
  };

  db.prepare(
    `
      UPDATE bookmarks
      SET url = ?, title = ?, description = ?, folder_id = ?, updated_at = ?
      WHERE user_id = ? AND id = ?
    `,
  ).run(
    updatedBookmark.url,
    updatedBookmark.title,
    updatedBookmark.description,
    updatedBookmark.folder_id,
    updatedBookmark.updated_at,
    userId,
    id,
  );

  return res.status(200).json(findBookmark(userId, id));
});

app.delete("/bookmarks/:id", (req, res) => {
  const userId = authenticatedUserId(req);
  const result = db
    .prepare("DELETE FROM bookmarks WHERE user_id = ? AND id = ?")
    .run(userId, Number(req.params.id));

  if (result.changes === 0) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;

